// ================================================
// COST SPIKE ANALYZER
// Compares today's spend to the rolling baseline
// ================================================

const billing = $('Fetch Daily Cost').first().json;
const baselineRows = $input.all().map(i => i.json);

// Current spend from the billing API
const todayCost = Number(billing.amount || billing.cost || billing.total || 0);
const currency = billing.currency || 'USD';
const service = billing.service || 'All Services';
const account = billing.account_id || billing.accountId || 'primary';

// Build rolling baseline from historical rows (trailing average)
const costs = baselineRows
  .map(r => Number(r.dailyCost || r.cost || 0))
  .filter(v => v > 0);

const sampleSize = costs.length;
const baselineAvg = sampleSize > 0
  ? costs.reduce((a, b) => a + b, 0) / sampleSize
  : 0;

// Percentage change vs baseline
const pctChange = baselineAvg > 0
  ? ((todayCost - baselineAvg) / baselineAvg) * 100
  : 0;

const threshold = 25; // alert if spend rises more than 25 percent

const isValid = todayCost > 0 && baselineAvg > 0 && sampleSize >= 3;
const isSpike = isValid && pctChange >= threshold;

return [{
  json: {
    runDate: new Date().toISOString().split('T')[0],
    processedAt: new Date().toISOString(),
    service,
    account,
    currency,
    todayCost: Number(todayCost.toFixed(2)),
    baselineAvg: Number(baselineAvg.toFixed(2)),
    pctChange: Number(pctChange.toFixed(1)),
    threshold,
    sampleSize,
    isValid,
    isSpike,
    deltaAmount: Number((todayCost - baselineAvg).toFixed(2))
  }
}];

